"css`
        :host {
            display: flex;
            flex: 1 1 0;
            flex-flow: column nowrap;
            padding: 0;
        }
        div#content-area {
            display: flex;
            flex: 1 1 0;
            align-content: start;
            flex-flow: row nowrap;
            position: relative;
        }
        div#toolbar {
            display: flex;
            flex-flow: column nowrap;
            align-items: center;
            width: 48px;
            background-color: var(--sl-color-gray-400);
        }
        div#table {
            display: flex;
            flex-flow: column nowrap;
            flex: 1 1 0;
        }
        div#table > div {
            display: flex;
            flex-flow: column nowrap;
            flex: 1 1 0;
            overflow-y: scroll;
        }
        table {
            margin: 0;
            font-size: var(--sl-font-size-x-small);
        }
        thead th {
            position: sticky;
            top: 0;
            background-color: gray;
            z-index: 1;
        }
        sl-spinner {
            position: absolute;
            top:  50%;
            left: 50%;
            transform: translate(-50%,-50%);
            font-size: 64px; 
            --track-width: 12px;
        }
    `"

